# Day 26: Decorators: Wrapping Functions with Reusable Logic
# Decorators
import time

# Basic decorator
def log_call(func):
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__}...")
        result = func(*args, **kwargs)
        print(f"  → returned {result}")
        return result
    return wrapper

@log_call
def add(a, b):
    return a + b

add(3, 5)

# Timer decorator
def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        elapsed = time.time() - start
        print(f"  {func.__name__} took {elapsed:.4f}s")
        return result
    return wrapper

@timer
def slow_sum(n):
    return sum(range(n))

print(f"Result: {slow_sum(1000000)}")
